import{_ as n,a as h,o as c,ag as i}from"./chunks/framework.RVu0gECZ.js";const m=JSON.parse('{"title":"Loại đầu vào thuộc tính","description":"","frontmatter":{},"headers":[],"relativePath":"attribute/attribute-input.md","filePath":"attribute/attribute-input.md","lastUpdated":1775811487000}'),d={name:"attribute/attribute-input.md"};function r(a,t,o,u,g,e){return c(),h("div",null,t[0]||(t[0]=[i('<h1 id="loai-đau-vao-thuoc-tinh" tabindex="-1">Loại đầu vào thuộc tính <a class="header-anchor" href="#loai-đau-vao-thuoc-tinh" aria-label="Permalink to &quot;Loại đầu vào thuộc tính&quot;">​</a></h1><p>Các thuộc tính có thể có các loại đầu vào khác nhau xác định không chỉ cách bạn nhập giá trị cho thuộc tính mà còn xác định cách người mua hàng có thể chọn thuộc tính trong trường hợp tùy chọn hoặc nhập giá trị.</p><p>Thuộc tính sản phẩm là tập hợp các đặc điểm xác định một sản phẩm hoặc một nhóm hàng hóa cụ thể. Điều này có nghĩa là kích thước, màu sắc, hương vị, loại bao bì, v.v. tạo thành các thuộc tính. Thuộc tính sản phẩm không chỉ là mô tả chung về sản phẩm mà còn nói lên giá trị khiến sản phẩm trở nên độc đáo.</p><table tabindex="0"><thead><tr><th>Bất động sản</th><th>Mô tả</th></tr></thead><tbody><tr><td>văn bản</td><td>Trường nhập văn bản một dòng.</td></tr><tr><td>Vùng văn bản</td><td>Trường nhập nhiều dòng để nhập các đoạn văn bản, chẳng hạn như mô tả sản phẩm.</td></tr><tr><td>Giá</td><td>Loại đầu vào này được sử dụng để tạo các trường giá ngoài các thuộc tính được xác định trước: Giá, Giá đặc biệt, Giá cấp và Chi phí.</td></tr><tr><td>Boolean</td><td>Hiển thị danh sách thả xuống với các tùy chọn được xác định trước là Có và Không.</td></tr><tr><td>Chọn</td><td>Hiển thị một tùy chọn để chọn một giá trị.</td></tr><tr><td>Chọn nhiều</td><td>Hiển thị danh sách thả xuống các giá trị chấp nhận nhiều lựa chọn.</td></tr><tr><td>Ngày</td><td>Hiển thị giá trị ngày ở định dạng ưa thích.</td></tr><tr><td>Ngày Giờ</td><td>Hiển thị giá trị ngày và giờ ở định dạng và múi giờ ưa thích.</td></tr><tr><td>Hình ảnh</td><td>Điều này được sử dụng để hiển thị hình ảnh. Thuộc tính hình ảnh có thể được loại trừ khỏi trình duyệt phương tiện của cửa hàng.</td></tr><tr><td>Tập tin</td><td>Thuộc tính tệp là một loại siêu dữ liệu mô tả và có thể sửa đổi cách hoạt động của tệp và/hoặc thư mục trong hệ thống tệp.</td></tr><tr><td>Hộp kiểm</td><td>Nó đại diện cho một trạng thái hoặc tùy chọn có thể được chuyển đổi.</td></tr></tbody></table>',4)]))}const s=n(d,[["render",r]]);export{m as __pageData,s as default};
